import React from "react";

const contacts = [
  { label: "📧 Email", value: "bhmidayosra@gmail.com", href: "mailto:bhmidayosra@gmail.com" },
  { label: "💼 LinkedIn", value: "linkedin.com/in/yosra-ben-hmida", href: "https://www.linkedin.com/in/yosra-ben-hmida/" },
  { label: "⌥ GitHub", value: "github.com/yosrabenhmidaa", href: "https://github.com/yosrabenhmidaa" },
  { label: "📍 Localisation", value: "Dar Chaabenne El Fehri, Tunisie", href: null },
  { label: "📞 Téléphone", value: "+216 25 705 519", href: "tel:+21625705519" },
];

export default function Contact() {
  return (
    <div className="contact-wrap">
      <div className="section-head reveal">
        <span className="section-label">Travaillons ensemble</span>
        <h2 className="section-title">Me contacter</h2>
        <div className="section-underline" style={{ margin: "1rem auto 0" }} />
      </div>

      <p className="contact-desc reveal" style={{ transitionDelay: "0.1s" }}>
        Je suis disponible pour des <strong style={{ color: "#c084fc" }}>alternances</strong>, stages ou collaborations.<br />
        N'hésitez pas à me contacter !
      </p>

      <div className="contact-list stagger-children">
        {contacts.map((item) =>
          item.href ? (
            <a
              key={item.label}
              href={item.href}
              target={item.href.startsWith("http") ? "_blank" : undefined}
              rel="noreferrer"
              className="contact-item reveal"
            >
              <span className="contact-label">{item.label}</span>
              <span className="contact-value">{item.value}</span>
            </a>
          ) : (
            <div key={item.label} className="contact-item reveal" style={{ cursor: "default" }}>
              <span className="contact-label">{item.label}</span>
              <span className="contact-value">{item.value}</span>
            </div>
          )
        )}
      </div>
    </div>
  );
}
